<?php
namespace Tests\Feature;
use App\Models\{Task,TaskActivityLog,TaskChecklist,User,Workspace};use App\Support\CurrentWorkspace;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class TaskCoreTest extends TestCase{use RefreshDatabase;private function member(string $role='workspace_owner'):array{$u=User::create(['name'=>fake()->name(),'email'=>fake()->unique()->safeEmail(),'password'=>'password','status'=>'active']);$w=Workspace::create(['uuid'=>(string)str()->uuid(),'name'=>'Acme','slug'=>'acme'.uniqid(),'status'=>'active','owner_id'=>$u->id,'edition'=>'saas']);$w->users()->attach($u->id,['role_key'=>$role,'status'=>'active','joined_at'=>now()]);app(CurrentWorkspace::class)->set($w);return[$u,$w];}private function asTenant($u,$w){return $this->actingAs($u)->withSession(['current_workspace_id'=>$w->id]);}public function test_workspace_owner_can_create_task():void{[$u,$w]=$this->member();$this->asTenant($u,$w)->post('/tasks',['title'=>'Ship module','priority'=>'medium','status'=>'new'])->assertRedirect();$this->assertDatabaseHas('tasks',['workspace_id'=>$w->id,'title'=>'Ship module','created_by'=>$u->id]);}public function test_manager_can_create_and_assign_task():void{[$m,$w]=$this->member('manager');$assignee=User::create(['name'=>'Staff','email'=>'s@example.com','password'=>'x','status'=>'active']);$w->users()->attach($assignee->id,['role_key'=>'staff','status'=>'active']);$this->asTenant($m,$w)->post('/tasks',['title'=>'Assign me','priority'=>'high','status'=>'todo','assignees'=>[$assignee->id]])->assertRedirect();$this->assertDatabaseHas('task_assignees',['workspace_id'=>$w->id,'user_id'=>$assignee->id]);}public function test_staff_cannot_assign_task_if_permission_missing():void{[$s,$w]=$this->member('staff');$other=User::create(['name'=>'Other','email'=>'o@example.com','password'=>'x','status'=>'active']);$w->users()->attach($other->id,['role_key'=>'staff','status'=>'active']);$this->asTenant($s,$w)->post('/tasks',['title'=>'Bad','priority'=>'medium','status'=>'new','assignees'=>[$other->id]])->assertForbidden();}public function test_workspace_a_user_cannot_see_workspace_b_task():void{[$a,$wa]=$this->member();[$b,$wb]=$this->member();$task=Task::withoutWorkspaceScope()->create(['workspace_id'=>$wb->id,'title'=>'Secret','priority'=>'medium','status'=>'new']);$this->asTenant($a,$wa)->get('/tasks/'.$task->id)->assertNotFound();}public function test_task_list_filters_by_status():void{[$u,$w]=$this->member();Task::create(['title'=>'Open','priority'=>'medium','status'=>'todo']);Task::create(['title'=>'Done','priority'=>'medium','status'=>'completed']);$this->asTenant($u,$w)->get('/tasks?status=completed')->assertOk()->assertSee('Done')->assertDontSee('Open');}public function test_checklist_comment_attachment_and_activity():void{Storage::fake('local');[$u,$w]=$this->member();$task=Task::create(['title'=>'Work','priority'=>'medium','status'=>'new','created_by'=>$u->id]);$this->asTenant($u,$w)->post("/tasks/{$task->id}/checklists",['title'=>'One'])->assertRedirect();$item=TaskChecklist::first();$this->asTenant($u,$w)->patch("/tasks/{$task->id}/checklists/{$item->id}",['is_completed'=>1])->assertRedirect();$this->asTenant($u,$w)->post("/tasks/{$task->id}/comments",['comment'=>'Looks good'])->assertRedirect();$this->asTenant($u,$w)->post("/tasks/{$task->id}/attachments",['attachment'=>UploadedFile::fake()->create('spec.pdf',10,'application/pdf')])->assertRedirect();$this->assertDatabaseHas('task_checklists',['id'=>$item->id,'is_completed'=>1]);$this->assertDatabaseHas('task_comments',['task_id'=>$task->id,'comment'=>'Looks good']);$this->assertDatabaseHas('task_attachments',['task_id'=>$task->id,'original_name'=>'spec.pdf']);$this->assertDatabaseHas('task_activity_logs',['task_id'=>$task->id,'action'=>'attachment_uploaded']);}public function test_status_change_logs_activity_and_dashboard_counts():void{[$u,$w]=$this->member();$task=Task::create(['title'=>'Due','priority'=>'medium','status'=>'new','due_date'=>today(),'created_by'=>$u->id]);$this->asTenant($u,$w)->put("/tasks/{$task->id}",['title'=>'Due','priority'=>'medium','status'=>'completed','due_date'=>today()->toDateString()])->assertRedirect();$this->assertDatabaseHas('task_activity_logs',['task_id'=>$task->id,'action'=>'status_changed']);$this->asTenant($u,$w)->get('/dashboard')->assertOk()->assertSee('Completed tasks')->assertSee('1');}public function test_task_number_is_unique_per_workspace():void{[$u,$w]=$this->member();$this->asTenant($u,$w)->post('/tasks',['title'=>'A','priority'=>'medium','status'=>'new']);$this->asTenant($u,$w)->post('/tasks',['title'=>'B','priority'=>'medium','status'=>'new']);$this->assertCount(2,Task::pluck('task_number')->unique());}}
